var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"아저씨, 안녕! 오늘 나한테 고백할 거라며?","JPN":"やっほー、おじさん！　今日私に告白するんでしょ？","ENG":"Hey, mister! So, today's the day you're gonna confess your feelings for me?","TWN":"嗨，大叔！今天你要向我告白嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"아냐…? 사적인 자리에 이성친구만 따로 부를 이유가 그것 말고 더 있나?","JPN":"違うの……？　プライベートで異性と二人っきりに会う理由って、それしかなくない？","ENG":"No...? Well, what other reason could there be to invite just me to a private meetup like this?","TWN":"不是嗎…？在私人場合單獨邀請異性朋友，除了這個還有其他理由嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"…라고 생각해봤는데, 한 가지 그럴싸한 결론에 다다랐단 말씀!","JPN":"……と思ってたけど、もう1つ可能性の高い理由を思いついたんだよね！","ENG":"...That's what I was thinking, anyway. But! I actually came to a way more convincing conclusion!","TWN":"……我這麼想過，然後得出了一個看似合理的結論！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"짜잔! 생일 축하해! 앤디 표 특제 생일케이크야! 나이는 몰라서 대충 큰 걸로 하나 꽂았어!","JPN":"じゃーん！　誕生日おめでとう！　アンディー特製の誕生日ケーキだよ！　歳は知らないから、大きいろうそくを適当に1つ立てといた！","ENG":"Ta-da! Happy birthday! This is a special Andy-original birthday cake! I didn't know your exact age, so I just stuck on one big candle!","TWN":"哇喔！生日快樂！這是安狄特製的生日蛋糕！因為不知道你的年齡，所以隨便插了一個大蠟燭！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"엑? 이것도 아냐?","JPN":"えつ？　これも違う？","ENG":"Huh? That's not it either?","TWN":"欸？這也不是嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그럼 남은 이유는 세상에서 제-일 지루하고 현학적인 비즈니스 토킹 때문이란 거네.","JPN":"じゃあ残りの可能性は、世界で一番退屈で鼻につくビジネストークだけか。","ENG":"Then the only explanation left is the most boring, academic, soul-sucking business talk.","TWN":"那麼剩下的理由，就是世界上最無聊的商務對話囉。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"뭐가 됐든, 이 케이크는 먹어도 돼. 이번엔 캡사이신 장난 같은 거 안 쳤으니까.","JPN":"どっちにしろ、このケーキは食べていいよ。今回は辛味成分を入れるとか、そういうことしてないから。","ENG":"Whatever the case, you can still eat the cake. No tricks with capsaicins or anything this time, I promise.","TWN":"不管怎樣，這個蛋糕可以吃。這次沒有惡作劇加辣椒粉。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"정 의심되면 나 먼저 먹는다? 아앙-","JPN":"信じられないなら、先に食べるよ？　あーん～","ENG":"If you don't trust me, I'll go first. Aaah-","TWN":"如果懷疑的話，我先吃？啊嗯-"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"으앗?!","JPN":"うわっ！？","ENG":"Huh?!","TWN":"啊？！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"갑자기 왜 그래? 내 걸 뺏어 먹을 정도로 배가 고팠던 거야?","JPN":"どうしたの？　私の分まで取って食べたいほどお腹空いてた？","ENG":"What was that for?! Were you really that hungry, you had to steal my bite?","TWN":"你怎麼了？餓到搶我的東西吃嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"날 위해 만들어준 거니까 내가 먼저 먹어야 한다… 라고?","JPN":"「私のために作ってもらったものだから、私が先に食べるべき」……？","ENG":"Because I made it just for you, you had to be the first... to eat it?","TWN":"因為是我為你做的，所以你應該先吃……是這樣嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"아하하, 아저씨도 제법 남자애스러운 면이 있구나?","JPN":"あはは、おじさんも案外少年っぽいとこがあるんだね。","ENG":"Ahaha, you've got a pretty boyish side after all, huh?","TWN":"哈哈，沒想到大叔也有些男子氣概呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그럼 이건 어때?","JPN":"じゃあこれはどうかな？","ENG":"Then how about this?","TWN":"那麼這個怎麼樣？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"방금 뺏어 먹은 케이크, 내 입술에 잔뜩 닿았지롱.","JPN":"今食べたケーキ、私の唇が触れてたんだよ～？","ENG":"The piece of cake you just stole? My lips were on it.","TWN":"剛剛搶來的蛋糕，我的嘴唇碰到了喔。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"위생적으로 신뢰하고 있으니 괜찮다니… 뭔가 실망스러우면서도 안심이 되는 대답이네.","JPN":"衛生的に信頼しているから大丈夫……って、なんか拍子抜けするけど、ほっとする反応だね。","ENG":"You trust me hygienically so it's fine...? That's such a disappointing yet weirdly comforting answer.","TWN":"看我蠻愛乾淨的，所以沒問題……這個回答讓人有些失望，但又感到安心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"뭐, 그런 반응이어야 우리 아저씨답지.","JPN":"ま、そういうとこがおじさんらしいかな。","ENG":"Well, that does sound like you, mister.","TWN":"不過，這種反應才像你嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"그럼 신뢰의 보답으로 나도 아저씨의 계약서에 사인 해줘야겠네!","JPN":"じゃあ信頼に応える意味で、私もおじさんの契約書にサインしてあげないと！","ENG":"In that case, I guess I'll return the favor and sign your contract!","TWN":"那麼作為信任的回報，我也要在大叔的合約上簽字囉！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"왜 그렇게 쉽게 결정하냐니, 그야…","JPN":"そう簡単に決めてもいいのかって？　だって……","ENG":"Why'd I decide so easily? Well...","TWN":"為什麼這麼輕易就做決定呢，那是因為…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"난 아저씨를 좋아하니까.","JPN":"私はおじさんのこと好きだから。","ENG":"Because I like you.","TWN":"因為我喜歡大叔。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NICK","text":{"KOREA":"좋아하는 사람의 곁에서 오래오래 있고 싶으니까.","JPN":"好きな人の傍に、これからもずっといたいから。","ENG":"I want to stay by your side. For a long, long time.","TWN":"因為我想長久地陪伴在喜歡的人身邊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NICK","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};